1 ‚Äì Datatype: Simple Variable
As you have already seen, values can be assigned to variables. For the assignment, &lt;- and = are equivalent:

#| '!! shinylive warning !!': |
#|   shinylive does not work in self-contained HTML documents.
#|   Please set `embed-resources: false` in your metadata.
#| standalone: true
#| viewerHeight: 220
library(shiny)
CHUNK_ID &lt;- "w1_c1"
ui &lt;- fluidPage(
  tags$script('Shiny.addCustomMessageHandler("chunkRun",function(m){window.parent.postMessage({type:"chunkDone",chunkId:m.chunkId},"*");});'),
  textAreaInput("code", "Assignments", value = "a &lt;- 2\nb &lt;- TRUE\n# or:\nb = TRUE\nname = 'Rosalinde'\na\nb\nname", width = '100%', height = '120px'),
  actionButton("run", "Run Code", class = "btn-success"),
  verbatimTextOutput("out"),
  uiOutput("success_msg")
)
server &lt;- function(input, output, session) {
  observeEvent(input$run, {
    session$sendCustomMessage("chunkRun", list(chunkId = CHUNK_ID))
    output$out &lt;- renderPrint({
      exprs &lt;- parse(text = input$code)
      for (e in exprs) { res &lt;- withVisible(eval(e)); if (!is.null(res$value) && res$visible) print(res$value) }
    })
  })
}
shinyApp(ui, server)

